Function: const { parseQueryParam } = require('./utils');

function filterProducts(products, query) {
  let filtered = products;

  // Filter by min_rating (if provided)
  if (query.min_rating) {
    const minRating = parseQueryParam(query.min_rating);
    filtered = filtered.filter(prod => {
      return prod.rating >= minRating;
    });
  }

  // Filter by max_price (if provided)
  if (query.max_price) {
    const maxPrice = parseQueryParam(query.max_price);
    filtered = filtered.filter(prod => {
      return prod.price <= maxPrice;
    });
  }

  return filtered;
}

module.exports = { filterProducts };
